{
  "verses": [
    {
      "n": 10,
      "column": "left",
      "text": "Un kad Jekkabs Raëli / wahjas/ bet Raëlet bija raschens\nfawas Mahtes Brahta Lahbana un statsts Gihmis.\nMeitu eeraudsija / un fawas\nMahtes Brahta Lahbana Awis/\ntad peegahje tas/ un nowehle to\nAkmini no tahs Akkas Zau-\numa."
    },
    {
      "n": 11,
      "column": "left",
      "text": "Un dsirdtja fawas Mah-\nes Brahta Lahbana Awis / un\nJekkabs skuhpsttja Raëli / un pa-\nehle fawu Balfi/ un raundaja."
    },
    {
      "n": 12,
      "column": "left",
      "text": "Un Jekkabs pafazzija Ra-\nei/ ka wiꞥſch winnas Tehwa\nBrahlis effus/ un ka wiꞥſch Re-\nekkas Dehis effus / tad tezzeja\n/ un pafazzija to fawam Teh-\nam."
    },
    {
      "n": 13,
      "column": "left",
      "text": "Un kad Lahbans tahs\nBehstis no Jekkaba / fawas\nLahfas Dehla / dsirdeja / tad\nzeja tas winnam pretti/ un\nkampe winnu/ un skuhpstija\nnnu/ un eetvedde winnu tawa\nmmâ. Tad isteize tas Lah-\nnain wiffas schahs Leetas."
    },
    {
      "n": 14,
      "column": "left",
      "text": "Un Lahbanas fazzija us\nnnu : Teefcham tu effi no\nnneem Kanleem/ un no man-\nMeesas/ nn wiꞥſch mitte pee\nzaur angoschu Mehnefi."
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un Lahbans fazzija us\nkabu : Jepfchu tu mans\nahlis effi / buhtu tadeht tu\nwelti kalpojis? fatti man/\nraffiti tu Algai?"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un Lahbanam bij diwi\nitas/ tahs wezzakas Wahrs\nLea / un tahs jaunnakas\nhrds bija Raële."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Bet Leas Azziis bija pa-\ndetu/ tad dohchu es tew winnu"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un Jekkabs mihteja to\nRaëli/ un fazzija : Es gribbu tew\nseptix Gaddus kalpoht/ par Ra-\neli tawn jaannaku Mettu."
    },
    {
      "n": 19,
      "column": "right",
      "text": "Tad fazzija Lahbans:\nLabbaki es tew to dohmu / ne ka\neß to zittam Wihran dohmu/ pa-\nleez pee mannis."
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un Jekkabs kalpoja par\nRaëli septix Gaddus / twisch\nschkitte tohs mag Deenas effo-\nschas / tik mihti tas to turreja."
    },
    {
      "n": 21,
      "column": "right",
      "text": "Un Jekkabs fazzija us\nLahbann: Dohd man mannu\nSeewu/ jo tahs Deenas irr pee-\npilditas / ka es pee tahs eemu."
    },
    {
      "n": 22,
      "column": "right",
      "text": "Tad japulzeja Lahbans\nwissus tahs Weetas Laudis/ un\npadarrija Weefibas."
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un Wakkara nehme wiꞥſch\nfawu Meitu Leiü/ un eetvedde to\npee winna/ un Jekkabs gahje pee\ntahs."
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un Lahbans dewe fawu\nKalponi Silpu Leni/ fawai Mei-\ntai par Kalpont."
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un tas notikfe Rihta/\ntad raugi/ ta bija Lea/ tad faz-\nzija wiꞥſch us Lahbann : Kas tas\nes par Raëli pee tew esmu kal-\npojis/ kam tu man effi peewthlis?"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Tad fazzija Lahbans:\nMubfu Semmê ne mehds to jau-\nnaku preeksch tahs Pirindsimtas\nisdoht."
    },
    {
      "n": 27,
      "column": "right",
      "text": "Beids ar schahs to Ned-\ntad dohchu es tew winnu\narrid-"
    }
  ],
  "confidence": "high",
  "notes": ""
}
